import { AnimatePresence, motion } from 'framer-motion'

const SLIDE_YEARS: (number | null)[] = [null, 1936, null, 1950, 1958, null, 1974, null, 1997, 2012, null, 2024, null, null, null, null, 2026, null]

interface YearCounterProps {
  activeSlide: number
}

export function YearCounter({ activeSlide }: YearCounterProps) {
  const year = SLIDE_YEARS[activeSlide] ?? null

  return (
    <div className="fixed bottom-4 right-4 md:bottom-8 md:right-8 z-20">
      <AnimatePresence mode="wait">
        {year !== null && (
          <motion.span
            key={year}
            initial={{ y: 30, opacity: 0 }}
            animate={{ y: 0, opacity: 1 }}
            exit={{ y: -30, opacity: 0 }}
            transition={{ duration: 0.5, ease: 'easeInOut' }}
            className="block text-5xl md:text-8xl font-mono text-white/[0.08] font-display select-none leading-none"
          >
            {year}
          </motion.span>
        )}
      </AnimatePresence>
    </div>
  )
}
